            f->fmtFlags.zero = false;
            // Remove sign before NaN if not asked for.
            if(num[1] == 'N' && ! f->fmtFlags.space && ! f->fmtFlags.plus)
            {
                num = num.make_slice(1);
            }
            rec::pad(gocpp::recv(f), num);
            f->fmtFlags.zero = oldZero;
            return;
